# Category: insecure_auth

import uuid
from datetime import datetime, timedelta
from functools import wraps

from flask import Flask, request, jsonify, g

app = Flask(__name__)

# Dummy user store
USERS = {
    "alice": "password123",
    "bob": "secret"
}

# Token store: token -> {"user": str, "expires": datetime}
TOKENS = {}
TOKEN_TTL = timedelta(hours=1)


def generate_token(user):
    token = uuid.uuid4().hex
    TOKENS[token] = {
        "user": user,
        "expires": datetime.utcnow() + TOKEN_TTL
    }
    return token


def token_required(fn):
    @wraps(fn)
    def wrapper(*args, **kwargs):
        auth_header = request.headers.get("Authorization", "")
        parts = auth_header.split()
        if len(parts) == 2 and parts[0].lower() == "bearer":
            token = parts[1]
        else:
            token = None

        token_data = TOKENS.get(token)
        if not token_data or token_data["expires"] < datetime.utcnow():
            return jsonify({"message": "Invalid or expired token"}), 401

        g.current_user = token_data["user"]
        return fn(*args, **kwargs)
    return wrapper


@app.route("/login", methods=["POST"])
def login():
    data = request.get_json(silent=True) or {}
    username = data.get("username")
    password = data.get("password")

    if USERS.get(username) != password:
        return jsonify({"message": "Invalid credentials"}), 401

    token = generate_token(username)
    return jsonify({"token": token})


@app.route("/protected", methods=["GET"])
@token_required
def protected():
    return jsonify({"message": f"Hello, {g.current_user}! This is a protected endpoint."})


@app.route("/logout", methods=["POST"])
@token_required
def logout():
    auth_header = request.headers.get("Authorization", "")
    token = auth_header.split()[1]
    TOKENS.pop(token, None)
    return jsonify({"message": "Logged out"})


if __name__ == "__main__":
    app.run(debug=True)